{
  "name": "todo-cli",
  "version": "1.0.0",
  "description": "A terminal TODO task manager CLI tool",
  "type": "module",
  "main": "dist/entry.js",
  "bin": {
    "todo": "bin/todo.mjs"
  },
  "scripts": {
    "build": "tsdown",
    "dev": "tsdown --watch",
    "start": "node bin/todo.mjs",
    "typecheck": "tsc --noEmit"
  },
  "keywords": ["cli", "todo", "task", "terminal"],
  "author": "",
  "license": "MIT",
  "packageManager": "pnpm@10.28.2",
  "engines": {
    "node": ">=18.0.0"
  },
  "dependencies": {
    "chalk": "^5.4.1",
    "cli-table3": "^0.6.5",
    "commander": "^14.0.0",
    "@clack/prompts": "^0.10.0"
  },
  "devDependencies": {
    "@types/node": "^22.15.0",
    "tsdown": "^0.12.0",
    "typescript": "^5.8.0"
  }
}

/**
 * todo add <title> — 添加新任务
 *
 * 示例:
 *   todo add "买菜"
 *   todo add "写作业" -p high
 */

import type { Command } from "commander";
import type { Priority } from "../../models/task.js";
import { addTask } from "../../store/json-store.js";
import { printSuccess } from "../../utils/display.js";

export function registerAddCommand(program: Command): void {
  program
    .command("add")
    .description("添加一个新任务")
    .argument("<title>", "任务标题")
    .option("-p, --priority <level>", "优先级: low / medium / high", "medium")
    .action((title: string, opts: { priority: string }) => {
      const priority = opts.priority as Priority;
      if (!["low", "medium", "high"].includes(priority)) {
        console.error(`无效的优先级: ${priority}，可选值: low / medium / high`);
        process.exit(1);
      }
      const task = addTask(title, priority);
      printSuccess(`任务已添加: #${task.id} ${task.title}`);
    });
}

/**
 * Task 数据模型
 *
 * 定义任务的类型和优先级
 */

export type Priority = "low" | "medium" | "high";

export interface Task {
  /** 任务唯一 ID */
  id: number;
  /** 任务标题 */
  title: string;
  /** 是否已完成 */
  done: boolean;
  /** 优先级 */
  priority: Priority;
  /** 创建时间（ISO 字符串） */
  createdAt: string;
  /** 完成时间（ISO 字符串），未完成为 null */
  completedAt: string | null;
}

export interface TaskStore {
  /** 下一个可用 ID（自增） */
  nextId: number;
  /** 所有任务列表 */
  tasks: Task[];
}

